const items = $input.all();
const products = items[0]?.json || [];

const transformed = products.map(p => ({
  printify_id: p.id?.toString(),
  name: p.title,
  category: (p.title || '').toLowerCase().includes('shirt') ? 'shirts' : (p.title || '').toLowerCase().includes('hoodie') ? 'hoodies' : (p.title || '').toLowerCase().includes('sweat') ? 'sweats' : (p.title || '').toLowerCase().includes('beanie') ? 'beanies' : (p.title || '').toLowerCase().includes('hat') ? 'hats' : 'shirts',
  description: p.description || '',
  price: (p.variants?.[0]?.price || 0) / 100,
  image_url: p.images?.[0]?.url || '',
  brand: 'imperium',
  in_stock: p.variants?.some(v => v.available > 0) || false
}));

return transformed;
